def test_tc_il_003_light_50(can_bus):
    msgs = collect_bcm_messages(can_bus, MONITOR_DURATION)
    assert all(get_light_level(m.data) == 50 for m in msgs)

def test_tc_il_004_light_75(can_bus):
    msgs = collect_bcm_messages(can_bus, MONITOR_DURATION)
    assert all(get_light_level(m.data) == 75 for m in msgs)

def test_tc_il_005_light_100(can_bus):
    msgs = collect_bcm_messages(can_bus, MONITOR_DURATION)
    assert all(get_light_level(m.data) == 100 for m in msgs)

def test_tc_il_006_no_underflow(can_bus):
    msgs = collect_bcm_messages(can_bus, MONITOR_DURATION)
    assert all(get_light_level(m.data) >= 0 for m in msgs)

def test_tc_il_007_no_overflow(can_bus):
    msgs = collect_bcm_messages(can_bus, MONITOR_DURATION)
    assert all(get_light_level(m.data) <= 100 for m in msgs)

def test_tc_il_009_periodicity(can_bus):
    msgs = collect_bcm_messages(can_bus, 1.0)
    assert len(msgs) >= MIN_EXPECTED_FRAMES
